import React from 'react';
import { FolderKanban, FileCode2, CheckCircle2, Clock } from 'lucide-react';

const mockProjects = [
  {
    name: 'Todo App',
    type: 'React',
    status: 'Completed',
    icon: <FileCode2 className="w-7 h-7 text-fuchsia-400" />,
  },
  {
    name: 'Portfolio Site',
    type: 'Next.js',
    status: 'In Progress',
    icon: <FileCode2 className="w-7 h-7 text-blue-400" />,
  },
  {
    name: 'Blog Platform',
    type: 'Vue.js',
    status: 'Completed',
    icon: <FileCode2 className="w-7 h-7 text-green-400" />,
  },
  {
    name: 'Landing Page',
    type: 'Vanilla JS',
    status: 'In Progress',
    icon: <FileCode2 className="w-7 h-7 text-yellow-400" />,
  },
];

function Projects() {
  return (
    <div className="min-h-screen bg-gradient-to-br from-[#18181b] via-[#23232a] to-[#1e1b4b] flex flex-col items-center py-12 px-2 animate-fade-in-up">
      <h1 className="text-4xl font-extrabold text-center mb-10 bg-gradient-to-r from-fuchsia-400 to-blue-500 bg-clip-text text-transparent flex items-center justify-center gap-2">
        <FolderKanban className="w-8 h-8 text-fuchsia-400 animate-pulse" /> Projects
      </h1>
      <div className="w-full max-w-6xl grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-8 animate-fade-in">
        {mockProjects.map((project, idx) => (
          <div
            key={project.name}
            className="bg-[#23232a] rounded-2xl shadow-lg p-6 flex flex-col items-center border border-purple-800 hover:scale-105 hover:border-fuchsia-500 transition-all duration-200 animate-pop-fade"
            style={{ animationDelay: `${0.1 + idx * 0.1}s` }}
          >
            {project.icon}
            <div className="mt-3 text-lg font-bold text-white">{project.name}</div>
            <div className="text-xs text-gray-400 mb-2">{project.type}</div>
            <div className={`flex items-center gap-1 text-sm font-semibold ${project.status === 'Completed' ? 'text-green-400' : 'text-yellow-400'}`}> 
              {project.status === 'Completed' ? <CheckCircle2 className="w-4 h-4" /> : <Clock className="w-4 h-4" />} 
              {project.status}
            </div>
          </div>
        ))}
      </div>
      {/* Animations */}
      <style>{`
        .animate-fade-in-up {
          animation: fadeInUp 1s cubic-bezier(0.4, 0, 0.2, 1) both;
        }
        .animate-fade-in {
          animation: fadeIn 1.2s cubic-bezier(0.4, 0, 0.2, 1) both;
        }
        .animate-pop-fade {
          animation: popFadeIn 1s cubic-bezier(0.4, 0, 0.2, 1) both;
        }
        @keyframes fadeInUp {
          from { opacity: 0; transform: translateY(40px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
        @keyframes popFadeIn {
          0% { opacity: 0; transform: translateY(40px) scale(0.95); }
          60% { opacity: 1; transform: translateY(-8px) scale(1.05); }
          100% { opacity: 1; transform: translateY(0) scale(1); }
        }
      `}</style>
    </div>
  );
}

export default Projects;
